     1	import { useAuth, useModelIndex } from '@rhino-dev/rhino-react';
     2	import { NavLink, useLocation } from 'react-router-dom';
     3	import type { ReactNode } from 'react';
     4	import { Icon } from './Icons';
     5	import { initials } from '../lib/format';
     6	import type { Project, Task } from '../types';
     7	
     8	export function AppShell({ children }: { children: ReactNode }) {
     9	  const { logout } = useAuth();
    10	  const orgSlug = (typeof localStorage !== 'undefined' && localStorage.getItem('rhino_organization_slug')) || '';
    11	
    12	  // Show counts in the sidebar — lightweight call that the lib caches.
    13	  const projects = useModelIndex<Project>('projects', { perPage: 100 });
    14	  const tasks    = useModelIndex<Task>('tasks',       { perPage: 100 });
    15	
    16	  const projectsCount = projects.data?.data?.length || null;
    17	  const tasksCount    = tasks.data?.data?.length    || null;
    18	
    19	  return (
    20	    <div className="shell">
    21	      <aside className="shell-sidebar">
    22	        <div className="brand">
    23	          <div className="brand-mark">R</div>
    24	          <div className="brand-name">TaskFlow <span>/web</span></div>
    25	        </div>
    26	        <nav className="nav">
    27	          <div className="nav-section">Workspace</div>
    28	          <Item to="/dashboard"  icon={<Icon.layout />}>Dashboard</Item>
    29	          <Item to="/projects"   icon={<Icon.eye />}    badge={projectsCount}>Projects</Item>
    30	          <Item to="/tasks"      icon={<Icon.task />}   badge={tasksCount}>Tasks</Item>
    31	          <Item to="/labels"     icon={<Icon.tag />}>Labels</Item>
    32	
    33	          <div className="nav-section" style={{ marginTop: 10 }}>Admin</div>
    34	          <Item to="/members"    icon={<Icon.users />}>Members</Item>
    35	          <Item to="/trash"      icon={<Icon.trash />}>Trash</Item>
    36	        </nav>
    37	        <div style={{ padding: 14, borderTop: '1px solid var(--border)', fontSize: 11, color: 'var(--fg-faint)' }}>
    38	          Powered by <span className="accent mono">@rhino-dev/rhino-react</span>
    39	        </div>
    40	      </aside>
    41	
    42	      <header className="shell-header">
    43	        <Breadcrumb />
    44	        <div className="header-actions">
    45	          {orgSlug && <span className="header-org-slug">/{orgSlug}</span>}
    46	          <UserChip />
    47	          <button className="btn btn-ghost btn-sm" onClick={() => logout()} title="Sign out">
    48	            <Icon.logout size={14} /> Sign out
    49	          </button>
    50	        </div>
    51	      </header>
    52	
    53	      <main className="shell-main">{children}</main>
    54	    </div>
    55	  );
    56	}
    57	
    58	function Item({ to, icon, badge, children }: { to: string; icon: ReactNode; badge?: number | null; children: ReactNode }) {
    59	  return (
    60	    <NavLink to={to} className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}>
    61	      <span className="icon">{icon}</span>
    62	      <span>{children}</span>
    63	      {badge != null && badge > 0 && <span className="badge">{badge}</span>}
    64	    </NavLink>
    65	  );
    66	}
    67	
    68	function Breadcrumb() {
    69	  const loc = useLocation();
    70	  const parts = loc.pathname.split('/').filter(Boolean);
    71	  if (parts.length === 0) return <span className="muted">Dashboard</span>;
    72	  return (
    73	    <div className="row faint">
    74	      {parts.map((p, i) => (
    75	        <span key={i}>
    76	          {i > 0 && <span style={{ margin: '0 6px' }}>/</span>}
    77	          <span style={{ color: i === parts.length - 1 ? 'var(--fg)' : undefined, textTransform: 'capitalize' }}>{p}</span>
    78	        </span>
    79	      ))}
    80	    </div>
    81	  );
    82	}
    83	
    84	function UserChip() {
    85	  // The current-user name is exposed by the LoginPage stashing it in localStorage.
    86	  const name  = typeof localStorage !== 'undefined' ? localStorage.getItem('rhino_user_name')  ?? 'User' : 'User';
    87	  const email = typeof localStorage !== 'undefined' ? localStorage.getItem('rhino_user_email') ?? '' : '';
    88	  return (
    89	    <div className="user-chip" title={email}>
    90	      <span className="avatar">{initials(name)}</span>
    91	      <span>{name}</span>
    92	    </div>
    93	  );
    94	}
